content.content:
1	//
2	//  ContactManagerApp.swift
3	//  ContactManager
4	//
5	//  SwiftUI entry point. Replaces the legacy AppDelegate / main.m / MainMenu.xib
6	//  AppKit launch path.
7	//
8	
9	import SwiftData
10	import SwiftUI
11	
12	@main
13	struct ContactManagerApp: App {
14	    @State private var loadState: ContainerLoadState
15	
16	    init() {
17	        _loadState = State(initialValue: Self.loadContainer())
18	    }
19	
20	    var body: some Scene {
21	        WindowGroup {
22	            switch loadState {
23	            case .ready(let container):
24	                ContentView()
25	                    .modelContainer(container)
26	            case .testing:
27	                EmptyView()
28	            case .failed(let message):
29	                StoreErrorView(message: message) {
30	                    loadState = Self.loadContainer(resettingStore: true)
31	                }
32	            }
33	        }
34	        // Detached single-contact window. The value type is the encoded
35	        // `PersistentIdentifier` string (the same scheme used by App
36	        // Intents/Spotlight) so it round-trips cleanly through
37	        // `OpenWindowAction` and SwiftUI's window-restoration store.
38	        WindowGroup(id: "contact", for: String.self) { $encodedID in
39	            switch loadState {
40	            case .ready(let container):
41	                ContactWindowView(encodedID: encodedID)
42	                    .modelContainer(container)
43	            case .testing, .failed:
44	                EmptyView()
45	            }
46	        }
47	        .defaultSize(width: 520, height: 640)
48	        Settings {
49	            // The Settings scene gets its own model container injection so
50	            // the default-group picker can @Query groups. When the store
51	            // hasn't loaded we point the user back to the main window
52	            // instead of showing an empty preferences pane.
53	            switch loadState {
54	            case .ready(let container):
55	                SettingsView()
56	                    .modelContainer(container)
57	            case .testing, .failed:
58	                Text("Open ContactManager to manage preferences.")
59	                    .padding()
60	                    .frame(width: 360, height: 120)
61	            }
62	        }
63	        .commands {
64	            CommandGroup(replacing: .newItem) {
65	                Button("New Contact") {
66	                    NotificationCenter.default.post(name: .newContactRequested, object: nil)
67	                }
68	                .keyboardShortcut("n", modifiers: .command)
69	            }
70	            CommandGroup(after: .pasteboard) {
71	                Button("Find Duplicates…") {
72	                    NotificationCenter.default.post(name: .findDuplicatesRequested, object: nil)
73	                }
74	                .keyboardShortcut("d", modifiers: [.command, .shift])
75	            }
76	            CommandGroup(replacing: .importExport) {
77	                Button("Import from Contacts…") {
78	                    NotificationCenter.default.post(name: .importSystemContactsRequested, object: nil)
79	                }
80	                .keyboardShortcut("m", modifiers: [.command, .shift])
81	                Button("Import vCard…") {
82	                    NotificationCenter.default.post(name: .importVCardRequested, object: nil)
83	                }
84	                .keyboardShortcut("i", modifiers: [.command, .shift])
85	                Button("Import CSV…") {
86	                    NotificationCenter.default.post(name: .importCSVRequested, object: nil)
87	                }
88	                Button("Export vCard…") {
89	                    NotificationCenter.default.post(name: .exportVCardRequested, object: nil)
90	                }
91	                .keyboardShortcut("e", modifiers: [.command, .shift])
92	            }
93	        }
94	    }
95	
96	    // MARK: - Container loading
97	
98	    private static func loadContainer(resettingStore: Bool = false) -> ContainerLoadState {
99	        // UI test mode is detected via env var and pre-empts the unit-test
100	        // guard below: XCUITest injects an automation-support library
101	        // that drags `XCTestCase` into the app's loaded classes, so the
102	        // `NSClassFromString` check would short-circuit to `.testing` and
103	        // render `EmptyView()`. The flag itself just forces a fresh disk
104	        // store; the rest of the load path is identical to production so
105	        // UI tests exercise the same code real users run.
106	        let isUITestMode = ProcessInfo.processInfo
107	            .environment["CONTACTMANAGER_UI_TEST_MODE"] != nil
108	
109	        if !isUITestMode {
110	            // When hosting the unit tests, skip building the app's model
111	            // container entirely so the test target owns the only
112	            // container in the process.
113	            let isUnitTesting = ProcessInfo.processInfo
114	                .environment["XCTestConfigurationFilePath"] != nil
115	                || NSClassFromString("XCTestCase") != nil
116	            if isUnitTesting { return .testing }
117	        }
118	
119	        if resettingStore || isUITestMode {
120	            deleteDefaultStore()
121	        }
122	
123	        let schema = Schema([Contact.self, ContactField.self, ContactGroup.self])
124	
125	        // Build a CloudKit-backed container when the iCloud capability is
126	        // present, and fall back to a local-only container otherwise so the
127	        // app still runs without iCloud.
128	        let container: ModelContainer
129	        var isLocalOnlyFallback = false
130	        do {
131	            // `.automatic` uses the project's iCloud container when an iCloud
132	            // entitlement is present; without one it still loads successfully
133	            // and behaves as a local-only store.
134	            let cloudConfiguration = ModelConfiguration(schema: schema, cloudKitDatabase: .automatic)
